## Code Example
```typescript
interface RateLimiter {
  tryAcquire(n: number): boolean
}

class TokenBucket implements RateLimiter {
  constructor(private capacity: number, private fillRate: number) {}
  tryAcquire(n: number): boolean { return true }
}
class LeakyBucket implements RateLimiter {
  constructor(private rate: number) {}
  tryAcquire(n: number): boolean { return true }
}
class SlidingWindow implements RateLimiter {
  constructor(private window: number) {}
  tryAcquire(n: number): boolean { return true }
}

type Factory = () => RateLimiter

class RateLimiterRegistry {
  private map = new Map<string, Factory>()
  register(name: string, factory: Factory) { this.map.set(name, factory) }
  create(name: string): RateLimiter {
    const f = this.map.get(name)
    if (!f) throw new Error(`Unknown rate limiter: ${name}`)
    return f()
