## Code Example

```typescript
type LogLevel = "debug"|"info"|"warn"|"error";

interface LogRecord {
  level: LogLevel;
  message: string;
  timestamp: number;
  context?: any;
}

interface Destination {
  emit(record: LogRecord): Promise<void>;
}

interface DestinationConfig {
  minLevel: LogLevel;
  formatter?: (record: LogRecord) => string;
}

class Logger {
  private destinations = new Map<string, { destination: Destination; config: DestinationConfig }>();

  register(name: string, destination: Destination, config: DestinationConfig): void {
    this.destinations.set(name, { destination, config });
  }

  unregister(name: string): void {
    this.destinations.delete(name);
  }

  async log(level: LogLevel, message: string, context?: any): Promise<void> {
    const record: LogRecord = {
      level,
      message,
      timestamp: Date.now(),
      context
    };

    const promises = Array.from(this.destinations.entries())
      .filter(([_, { config }]) => this.shouldLog(record.level, config.minLevel))
      .map(async ([_, { destination, config }]) => {
        try {
          const formattedRecord = config.formatter ? config.formatter(record) : record;
          await destination.emit(formattedRecord);
        } catch (error) {
          console.error(`Destination failed:`, error);
        }
      });

    await Promise.allSettled(promises);
  }

  private shouldLog(recordLevel: LogLevel, minLevel: LogLevel): boolean {
    const levels: Record<LogLevel, number> = { debug: 0, info: 1, warn: 2, error: 3 };
    return levels[recordLevel] >= levels[minLevel];
  }
}
```

