interface Policy {
  boolean evaluate(User user, Resource resource, Action action);
  String name();
}
class PolicyRegistry {
  private final java.util.concurrent.atomic.AtomicReference<java.util.Map<String, Policy>> policies =
      new java.util.concurrent.atomic.AtomicReference<>(java.util.Collections.emptyMap());

  public void register(String name, Policy p) {
    var next = new java.util.HashMap<>(policies.get());
    next.put(name, p);
    policies.set(java.util.Collections.unmodifiableMap(next));
  }

  public boolean evaluate(User user, Resource resource, Action action) {
    for (Policy p : policies.get().values()) {
      if (p.evaluate(user, resource, action)) return true;
    }
    return false;
  }

  public void reload(java.util.Map<String, Policy> newPolicies) {
    policies.set(java.util.Collections.unmodifiableMap(new java.util.HashMap<>(newPolicies)));
  }
}
