- Trade-offs: O(1) lookups, eviction latency, policy state maintenance

## Code Example

```javascript
// Minimal eviction policy interface and implementations
class EvictionPolicy {
  accessed(key) { /* optional */ }
  evictKey(store, capacity) { throw new Error('not implemented') }
}

class LRUPolicy extends EvictionPolicy {
  constructor() { this.order = new Map(); }
  accessed(key) { if (this.order.has(key)) this.order.delete(key); this.order.set(key, true); }
  evictKey(store, capacity) {
    if (store.size <= capacity) return null;
    for (let k of this.order.keys()) {
      if (store.has(k)) return k;
    }
    return store.keys().next().value || null;
  }
}

class FIFOPolicy extends EvictionPolicy {
  constructor() { this.order = new Map(); }
  accessed(key) { /* FIFO does not update on access */ }
  evictKey(store, capacity) {
    if (store.size <= capacity) return null;
    for (let k of this.order.keys()) {
      if (store.has(k)) return k;
    }
    return store.keys().next().value || null;
  }
  registerInsert(key) { if (!this.order.has(key)) this.order.set(key, true); }
}

class EvictionRegistry {
  constructor() { this.factories = new Map(); }
  register(name, factory) { this.factories.set(name, factory); }
  create(name) { const f = this.factories.get(name); return f ? f() : null; }
}

class Cache {
  constructor(capacity, registry, policyName='lru') {
    this.capacity = capacity;
    this.store = new Map();
    this.registry = registry;
    this.policy = registry.create(policyName) || new LRUPolicy();
  }
  setPolicy(name) { const p = this.registry.create(name); if (p) this.policy = p; }
  put(key, value) {
    this.store.set(key, value);
    if (this.policy && typeof this.policy.registerInsert === 'function') {
      this.policy.registerInsert(key);
    }
    while (this.store.size > this.capacity) {
      const k = this.policy.evictKey(this.store, this.capacity);
      if (k == null) break;
      this.store.delete(k);
    }
  }
  get(key) {
    if (!this.store.has(key)) return undefined;
    const v = this.store.get(key);
    if (typeof this.policy.accessed === 'function') this.policy.accessed(key);
    return v;
  }
}
```

