interface RetryPolicy {
  shouldRetry(attempt: number, err: any): boolean;
  nextDelay(attempt: number, err?: any): number;
}
class LinearPolicy implements RetryPolicy {
  constructor(private delay: number, private max: number) {}
  shouldRetry(attempt: number) { return attempt < this.max; }
  nextDelay(_attempt: number) { return this.delay; }
}
class ExponentialPolicy implements RetryPolicy {
  constructor(private base: number, private factor: number, private cap: number) {}
  shouldRetry(attempt: number) { return attempt * this.factor < this.cap; }
  nextDelay(attempt: number) { return Math.min(this.base * Math.pow(this.factor, attempt - 1), this.cap); }
}
```

