class EditorOriginator {
  constructor(text = "") { this.text = text; }
  createMemento() { return new EditorMemento(this.text); }
  restore(m) { this.text = m.getState(); }
  insert(pos, ch) { this.text = this.text.slice(0, pos) + ch + this.text.slice(pos); }
  delete(pos, len) { this.text = this.text.slice(0, pos) + this.text.slice(pos + len); }
}
class EditorMemento { constructor(state) { this._state = state; } getState() { return this._state; } }
class Caretaker {
  constructor() { this.history = []; this.index = -1; }
  push(m) { this.history = this.history.slice(0, this.index + 1).concat([m]); this.index++; }
  undo() { if (this.index <= 0) return null; this.index--; return this.history[this.index + 1]; }
  redo() { if (this.index + 1 >= this.history.length) return null; this.index++; return this.history[this.index]; }
}
```

